sql:
SELECT location_id
FROM locations_analysis
WHERE sales_trend = 'decreasing';

external_knowledge:
Sales performance includes total and average sales;
Foot traffic includes total visits and average daily visits;
Inventory levels include total and average quantity of items;
Promotion activities include the number of promotions and average discount rate;
A retail location's business type refers to its category name (e.g., Toy / Game Store).;

- "retail jewels" refers to retail locations;
- "category of shining stars" corresponds to category ID 2;
- "day’s sales" refers to the total sales;
- "crowd count" refers to the number of people counted at the location;
- "high or low traffic beacons" indicates categorizing locations as 'High' or 'Low' based on foot traffic;
- "bustling about" means the number of people counted is greater than 2000;
- "worthy of being crowned" means the locations are selected based on the specified conditions;
- "no crowd data" means there is no foot traffic data available, treated as 'Low' traffic.

"retail spots" refers to retail locations;
"seen an uptick in visitors" means the foot traffic trend is increasing;
"consistent or growing sales performance" indicates the sales trend is either steady or increasing.

sql:
SELECT locations.name, sales_data.total_sales
FROM locations
JOIN sales_data ON locations.location_id = sales_data.location_id;

SELECT COUNT(*) 
FROM sales_data 
WHERE location_id = (SELECT location_id FROM locations WHERE name = 'The LEGO Store');

SELECT locations.name, categories.category_name 
FROM locations 
INNER JOIN categories ON locations.category_id = categories.category_id;

SELECT l.location_id, l.name
FROM locations l
JOIN locations_analysis la ON l.location_id = la.location_id
WHERE la.sales_trend > (
    SELECT AVG(sales_trend)
    FROM locations_analysis
) AND la.traffic_trend < (
    SELECT AVG(traffic_trend)
    FROM locations_analysis
);

SELECT location_id 
FROM locations_access 
WHERE user_id = 1 AND access_date = '2023-05-01';
